using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 5);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 3);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_TotalPages_ExactDivision()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 5);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages=2, PageIndex=2
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages=2, PageIndex=1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_PartialItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.True(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
            Assert.Empty(result);
        }

        [Fact]
        public void Create_SingleItem()
        {
            var source = new[] { 42 }.AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result.First());
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

using System;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        // --- Person / Student / Instructor ---

        [Fact]
        public void Person_FullName_CombinesLastAndFirst()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal(1, student.ID);
            Assert.Equal("Doe, Jane", student.FullName);
            Assert.Equal(new DateTime(2023, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "Kim",
                FirstMidName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11)
            };

            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Kim, Abercrombie", instructor.FullName);
            Assert.Equal(new DateTime(1995, 3, 11), instructor.HireDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new[] { new Enrollment { EnrollmentID = 1 } }
            };
            Assert.Single(student.Enrollments);
        }

        [Fact]
        public void Instructor_CourseAssignments_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new[] { new CourseAssignment { CourseID = 1 } }
            };
            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_OfficeAssignment_CanBeSet()
        {
            var instructor = new Instructor
            {
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        // --- Course ---

        [Fact]
        public void Course_Properties()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties()
        {
            var dept = new Department { DepartmentID = 1, Name = "Engineering" };
            var course = new Course { CourseID = 1, Department = dept };
            Assert.Equal("Engineering", course.Department.Name);
        }

        // --- Enrollment ---

        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment { EnrollmentID = 1 };
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_GradeValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        [Fact]
        public void Enrollment_NavigationProperties()
        {
            var student = new Student { ID = 1, LastName = "Test", FirstMidName = "User" };
            var course = new Course { CourseID = 100, Title = "Math" };
            var enrollment = new Enrollment
            {
                StudentID = 1,
                CourseID = 100,
                Student = student,
                Course = course,
                Grade = Grade.A
            };

            Assert.Equal("Test, User", enrollment.Student.FullName);
            Assert.Equal("Math", enrollment.Course.Title);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        // --- Department ---

        [Fact]
        public void Department_Properties()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 3
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Mathematics", dept.Name);
            Assert.Equal(100000m, dept.Budget);
            Assert.Equal(3, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_CanBeSet()
        {
            var dept = new Department { RowVersion = new byte[] { 1, 2, 3 } };
            Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
        }

        // --- CourseAssignment ---

        [Fact]
        public void CourseAssignment_CompositeKey()
        {
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 100 };
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        // --- OfficeAssignment ---

        [Fact]
        public void OfficeAssignment_Properties()
        {
            var oa = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Smith 17", oa.Location);
        }

        // --- Notification ---

        [Fact]
        public void Notification_Properties()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
