            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
            var saved = _context.Instructors.First(i => i.LastName == "NewInstructor");
            Assert.Single(_context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID));
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            SeedData();
            _controller.ModelState.AddModelError("LastName", "Required");
