using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("User", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First();
            Assert.Equal("Prof", retrieved.LastName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.First();
            Assert.Equal("Physics", retrieved.Title);
            Assert.Equal(dept.DepartmentID, retrieved.DepartmentID);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);

            var dept = new Department { Name = "Dept", Budget = 1000, StartDate = new DateTime(2020, 1, 1) };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 1001, Title = "Course1", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First();
            Assert.Equal(Grade.A, retrieved.Grade);
            Assert.Equal(student.ID, retrieved.StudentID);
        }

        [Fact]
        public void CourseAssignment_CompositeKey()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };
            _context.Instructors.Add(instructor);

            var dept = new Department { Name = "Dept", Budget = 1000, StartDate = new DateTime(2020, 1, 1) };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 1001, Title = "Course1", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.First();
            Assert.Equal(instructor.ID, retrieved.InstructorID);
            Assert.Equal(course.CourseID, retrieved.CourseID);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.First();
            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal(instructor.ID, retrieved.InstructorID);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("CREATE", retrieved.Operation);
        }

        [Fact]
        public void DbInitializer_SeedsData()
        {
            var freshContext = TestDbContextFactory.Create();
            DbInitializer.Initialize(freshContext);

            Assert.Equal(8, freshContext.Students.Count());
            Assert.Equal(5, freshContext.Instructors.Count());
            Assert.Equal(4, freshContext.Departments.Count());
            Assert.Equal(7, freshContext.Courses.Count());
            Assert.True(freshContext.Enrollments.Any());
            Assert.True(freshContext.CourseAssignments.Any());
            Assert.True(freshContext.OfficeAssignments.Any());

            freshContext.Dispose();
        }

        [Fact]
        public void DbInitializer_DoesNotReseed()
        {
            var freshContext = TestDbContextFactory.Create();
            DbInitializer.Initialize(freshContext);
            DbInitializer.Initialize(freshContext); // Call again

            // Should still be the same count
            Assert.Equal(8, freshContext.Students.Count());

            freshContext.Dispose();
        }
    }
}
