            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_AllowedImageExtensions()
        {
            var dept = SeedDepartment();
            var extensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };

            foreach (var ext in extensions)
            {
                var course = new Course
                {
                    CourseID = 2000 + Array.IndexOf(extensions, ext),
                    Title = $"Course{ext}",
                    Credits = 3,
                    DepartmentID = dept.DepartmentID
                };

