using System;
using System.Collections.Generic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            // Drain static queue from prior tests
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after test
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);
            var dict = json.GetType().GetProperty("success")?.GetValue(json);
            Assert.Equal(true, dict);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            svc.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            var count = json.GetType().GetProperty("count")?.GetValue(json);
            Assert.Equal(2, count);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var json = result.Value;
            var count = json.GetType().GetProperty("count")?.GetValue(json);
            Assert.Equal(10, count);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = result.Value;
            var success = json.GetType().GetProperty("success")?.GetValue(json);
            Assert.Equal(true, success);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

using System;
