using System;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        // --- Person / Student / Instructor ---

        [Fact]
        public void Person_FullName_CombinesLastAndFirst()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal(1, student.ID);
            Assert.Equal("Doe, Jane", student.FullName);
            Assert.Equal(new DateTime(2023, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "Kim",
                FirstMidName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11)
            };

            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Kim, Abercrombie", instructor.FullName);
            Assert.Equal(new DateTime(1995, 3, 11), instructor.HireDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new[] { new Enrollment { EnrollmentID = 1 } }
            };
            Assert.Single(student.Enrollments);
        }

        [Fact]
        public void Instructor_CourseAssignments_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new[] { new CourseAssignment { CourseID = 1 } }
            };
            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_OfficeAssignment_CanBeSet()
        {
            var instructor = new Instructor
            {
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        // --- Course ---

        [Fact]
        public void Course_Properties()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties()
        {
            var dept = new Department { DepartmentID = 1, Name = "Engineering" };
            var course = new Course { CourseID = 1, Department = dept };
            Assert.Equal("Engineering", course.Department.Name);
