using System;
using System.Linq;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from prior tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain after test to keep things clean
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "AdminUser");

            var notification = _service.ReceiveNotification();
            Assert.Equal("AdminUser", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("Department", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            Assert.NotNull(first);

            var second = _service.ReceiveNotification();
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory; just verify no exception
            _service.MarkAsRead(999);
        }

        [Fact]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", null, EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", "", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", "   ", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllReceivable()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.Equal(5, count);
        }

        [Fact]
        public void SendNotification_NoDisplayName_CreateMessage()
        {
            _service.SendNotification("Instructor", "10", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Instructor (ID: 10) has been created", n.Message);
        }

        [Fact]
        public void SendNotification_NoDisplayName_UpdateMessage()
        {
            _service.SendNotification("Instructor", "10", EntityOperation.UPDATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Instructor (ID: 10) has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_NoDisplayName_DeleteMessage()
        {
            _service.SendNotification("Instructor", "10", EntityOperation.DELETE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Instructor (ID: 10) has been deleted", n.Message);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should not throw
        }
    }
}

