using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            // Seed students
            _context.Students.Add(new Student
            {
                LastName = "Test1",
                FirstMidName = "A",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.Students.Add(new Student
            {
                LastName = "Test2",
                FirstMidName = "B",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.Students.Add(new Student
            {
                LastName = "Test3",
                FirstMidName = "C",
                EnrollmentDate = new DateTime(2024, 9, 1)
            });
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Models.SchoolViewModels.EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);
            Assert.Equal(2, model.First(g => g.EnrollmentDate == new DateTime(2023, 9, 1)).StudentCount);
            Assert.Equal(1, model.First(g => g.EnrollmentDate == new DateTime(2024, 9, 1)).StudentCount);
        }

        [Fact]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
