using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2010, 9, 1) },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2012, 9, 1) },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2013, 9, 1) },
                new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2012, 9, 1) },
                new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2012, 9, 1) }
            );
            _context.SaveChanges();
        }

        // --- Index ---

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model.First().LastName);
            Assert.Equal("Li", model.Last().LastName);
        }

        [Fact]
        public void Index_NameDescSort()
        {
            SeedStudents();

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Li", model.First().LastName);
            Assert.Equal("Alexander", model.Last().LastName);
        }

        [Fact]
        public void Index_DateSort()
        {
            SeedStudents();

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(new DateTime(2010, 9, 1), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort()
        {
            SeedStudents();

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(new DateTime(2013, 9, 1), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_SearchByLastName()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alonso", model.First().LastName);
        }

        [Fact]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "ZZZ_NoMatch", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Empty(model);
        }

        [Fact]
        public void Index_NullSearch_UsesCurrentFilter()
        {
            SeedStudents();

            var result = _controller.Index(null, "Li", null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_NewSearch_ResetsToPage1()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "A", 3) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            SeedStudents();

            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);

            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_SetsCurrentFilter()
        {
            SeedStudents();

            _controller.Index(null, null, "test", null);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Empty(model);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Students);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
            Assert.Empty(_context.Students);
        }

        [Fact]
        public void Create_POST_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Edit (GET) ---

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsStudentView()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- Edit (POST) ---

        [Fact]
        public void Edit_POST_ValidUpdate_RedirectsToIndex()
        {
            SeedStudents();
            var student = _context.Students.First();
            // Detach so edit can re-attach
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = student.ID,
                LastName = "UpdatedName",
                FirstMidName = student.FirstMidName,
                EnrollmentDate = student.EnrollmentDate
            };

            var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            SeedStudents();
            var student = _context.Students.First();
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = default(DateTime)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Delete (GET) ---

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsStudentView()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- DeleteConfirmed (POST) ---

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            SeedStudents();
            var student = _context.Students.First();
            int initialCount = _context.Students.Count();

            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, _context.Students.Count());
        }
    }
}

