using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedData()
        {
            var instructor = new Instructor
            {
                LastName = "Harui",
                FirstMidName = "Roger",
                HireDate = new DateTime(1998, 7, 1)
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            _context.Departments.AddRange(
                new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor.ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1) },
                new Department { Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1) }
            );
            _context.SaveChanges();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            SeedData();

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Empty(model);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsDepartment()
        {
            SeedData();
            var dept = _context.Departments.First();

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_GET_ReturnsView()
        {
            SeedData();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            SeedData();
            var department = new Department
            {
                Name = "NewDept",
                Budget = 50000,
                StartDate = new DateTime(2024, 1, 1)
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            SeedData();
            _controller.ModelState.AddModelError("Name", "Required");
