using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedData()
        {
            var instructors = new[]
            {
                new Instructor { LastName = "Abercrombie", FirstMidName = "Kim", HireDate = new DateTime(1995, 3, 11),
                    CourseAssignments = new List<CourseAssignment>() },
                new Instructor { LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = new DateTime(2002, 7, 6),
                    OfficeAssignment = new OfficeAssignment { Location = "Smith 17" },
                    CourseAssignments = new List<CourseAssignment>() },
                new Instructor { LastName = "Harui", FirstMidName = "Roger", HireDate = new DateTime(1998, 7, 1),
                    CourseAssignments = new List<CourseAssignment>() }
            };
            _context.Instructors.AddRange(instructors);
            _context.SaveChanges();

            var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = instructors[2].ID };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Assign course to first instructor
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructors[0].ID, CourseID = course.CourseID });
            _context.SaveChanges();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithInstructors()
        {
            SeedData();

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            SeedData();
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);

            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Empty(model.Instructors);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            SeedData();
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_GET_ReturnsView()
        {
            SeedData(); // Seed courses for the dropdown

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AssignsCourses()
        {
            SeedData();
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
